import React, { useState, useEffect } from 'react';
import { Routes, Route, useLocation, Link, useNavigate } from 'react-router-dom';
import Home from './pages/Home';
import Search from './pages/Search';
import Add from './pages/Add';
import Bookings from './pages/Bookings';
import Profile from './pages/Profile';
import Chat from './pages/Chat';
import Register from './pages/Register';
import Login from './pages/Login';
import Listings from './pages/Listings';
import ListingDetails from './pages/ListingDetails';
import Explore from './pages/Explore';
import MyListings from './pages/MyListings';
import Wallet from './pages/Wallet';
import Settings from './pages/Settings';
import HelpCenter from './pages/HelpCenter';
import BottomNavigation from './components/BottomNavigation';
import { AuthProvider, useAuth } from './context/AuthContext';
import { ListingProvider } from './context/ListingContext';
import { BookingProvider } from './context/BookingContext';
import { ChatProvider } from './context/ChatContext';

// SVG Icons as React components
const HomeIcon = ({ className }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" />
  </svg>
);

const SearchIcon = ({ className }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
  </svg>
);

const AddIcon = ({ className }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
  </svg>
);

const BookIcon = ({ className }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" />
  </svg>
);

const PersonIcon = ({ className }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
  </svg>
);

const ChatIcon = ({ className }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" />
  </svg>
);

const AppContent = () => {
  const { user } = useAuth();
  const location = useLocation();
  const navigate = useNavigate();
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);

  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth < 768);
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);



  return (
    <div className="bg-gray-50 min-h-screen pb-16 md:pb-0">
      {/* Desktop Navigation */}
      {!isMobile && (
        <nav className="hidden md:flex items-center justify-between px-6 py-4 bg-white shadow-sm sticky top-0 z-40">
          <div className="flex items-center">
            <div className="bg-gradient-to-r from-teal-600 to-teal-500 text-white font-bold rounded-lg px-3 py-2 mr-6">
              RenThing
            </div>
            <div className="relative">
              <input 
                type="text" 
                placeholder="Search for items or services..." 
                className="pl-10 pr-4 py-2 border border-gray-300 rounded-full w-64 focus:outline-none focus:ring-2 focus:ring-teal-500 focus:border-transparent"
                onKeyPress={(e) => {
                  if (e.key === 'Enter') {
                    navigate('/search');
                  }
                }}
              />
              <SearchIcon className="h-5 w-5 text-gray-400 absolute left-3 top-2.5" />
            </div>
          </div>
          <div className="flex items-center space-x-6">
            <Link to="/explore" className="text-gray-600 hover:text-teal-600">Explore</Link>
            <button 
              onClick={() => navigate('/add')}
              className="bg-gradient-to-r from-teal-600 to-teal-500 text-white px-4 py-2 rounded-full font-medium hover:bg-teal-600 transition"
            >
              Rent Out
            </button>
            <div className="flex items-center space-x-2">
              <div className="w-8 h-8 rounded-full bg-teal-100 flex items-center justify-center">
                <PersonIcon className="h-5 w-5 text-teal-600" />
              </div>
              <span className="text-gray-700">{user?.name || 'Guest'}</span>
            </div>
          </div>
        </nav>
      )}

      {/* Main Content */}
      <div className="relative">
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/search" element={<Search />} />
